@@ -37,7 +37,7 @@ html {

 /* Dark mode (default) colors and backgrounds */
 :root {
-  --sl-color-accent-low: #0c214d; /* Specific dark accent, no direct Tenzir token */
+  --sl-color-accent-low: color-mix(in srgb, var(--tnz-primary-600) 25%, var(--tnz-neutral-800));
   --sl-color-accent: var(--tnz-primary-500);
   --sl-color-accent-high: var(--tnz-primary-300);
   --sl-color-white: var(--tnz-neutral-100); /* Main text color */
@@ -56,7 +56,7 @@ html {

   --tnz-nav-hover-bg: rgba(255, 255, 255, 0.08);
   --tnz-nav-active-bg: rgba(255, 255, 255, 0.15);
-  --tnz-nav-active-border: var(--sl-color-accent);
+  --tnz-nav-active-border: var(--tnz-primary-500);
 }

 /* Light mode overrides */
@@ -82,7 +82,7 @@ html {

   --tnz-nav-hover-bg: rgba(0, 0, 0, 0.04);
   --tnz-nav-active-bg: rgba(0, 0, 0, 0.08);
-  --tnz-nav-active-border: var(--sl-color-accent);
+  --tnz-nav-active-border: var(--tnz-primary-500);

   --sl-color-text-invert: var(--sl-color-black);
 }
